mapper.select:
SELECT id, user_id, version, source, status, error_msg, raw_text, parsed_data,
       file_name, file_url, file_size, is_active, create_time, update_time
FROM resume WHERE id = #{id}

SELECT id, user_id, version, source, status, error_msg,
       file_name, file_url, file_size, is_active, create_time, update_time
FROM resume WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{size}
